    "ReportStringId.Wizard_ReportColorScheme_JeansBlue"                 = "Dżinsowy niebieski"
    "ReportStringId.Wizard_ReportColorScheme_LightGreen"                = "Jasna zieleń"
    "ReportStringId.Wizard_ReportColorScheme_Raspberry"                 = "Malinowy"
    "ReportStringId.Wizard_ReportColorScheme_Violet"                    = "Fioletowy"
    # ── ExpressionCollectionEditor ────────────────────────────────────────────
    "ReportStringId.ExpressionCollectionEditor_Msg_ExpressionUnavailable" = "Aby określić wyrażenie, musisz wybrać żądany węzeł lub rozwinąć go w celu modyfikacji."
    # ── ErrorManagement / ScriptEditor ───────────────────────────────────────
    "ReportStringId.ErrorManagement"                                    = "Zarządzanie błędami raportu"
    "ReportStringId.ScriptEditor_ScriptHasBeenChanged"                  = "Dziennik błędów nie dotyczy aktualnego skryptu (skrypt zmieniono po ostatniej weryfikacji).`r`nAby zobaczyć aktualne błędy, kliknij ponownie przycisk Sprawdź."
